#include <stdio.h>
#include <string.h>
#include <ctype.h>

int cmp(const void *a, const void *b) {
    const int *pa = (const int *)a;
    const int *pb = (const int *)b;
    if (pa[1] != pb[1]) return pa[1] - pb[1]; // frequency ascending
    return pa[0] - pb[0]; // letter ascending
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char freqSeq[27];
    char text[150005];
    for (int tc = 0; tc < T; ++tc) {
        fgets(freqSeq, sizeof(freqSeq), stdin);
        size_t len = strlen(freqSeq);
        if (len && freqSeq[len-1] == '\n') freqSeq[--len] = '\0';
        fgets(text, sizeof(text), stdin);
        len = strlen(text);
        if (len && text[len-1] == '\n') text[--len] = '\0';
        int cnt[26] = {0};
        for (size_t i = 0; i < len; ++i) {
            if (isalpha((unsigned char)text[i])) {
                cnt[tolower((unsigned char)text[i]) - 'a']++;
            }
        }
        int arr[26][2]; // [letter, count]
        for (int i = 0; i < 26; ++i) {
            arr[i][0] = i;
            arr[i][1] = cnt[i];
        }
        qsort(arr, 26, sizeof(arr[0]), cmp);
        char map[26];
        for (int i = 0; i < 26; ++i) {
            int cipherIdx = arr[i][0];
            map[cipherIdx] = freqSeq[i];
        }
        for (size_t i = 0; i < len; ++i) {
            char c = text[i];
            if (isalpha((unsigned char)c)) {
                char low = tolower((unsigned char)c);
                char dec = map[low - 'a'];
                if (isupper((unsigned char)c)) dec = toupper((unsigned char)dec);
                putchar(dec);
            } else {
                putchar(c);
            }
        }
        putchar('\n');
    }
    return 0;
}

