        vector<pair<int,int>> v; // (letter, count)
        for(int i=0;i<26;++i) v.push_back({i,cnt[i]});
        sort(v.begin(), v.end(), [](auto &a, auto &b){
            if(a.second!=b.second) return a.second<b.second; // freq asc
            return a.first<b.first; // letter asc
        });
        char mp[26];
        for(int i=0;i<26;++i) mp[v[i].first] = freqSeq[i];
        for(char c: text){
            if(isalpha(static_cast<unsigned char>(c))){
                char low = tolower(c);
                char dec = mp[low-'a'];
                if(isupper(c)) dec = toupper(dec);
                cout<<dec;
            } else cout<<c;
        }
        if(T) cout<<'\n';
    }
    return 0;
}

