import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            String freqSeq = br.readLine();
            String text = br.readLine();
            int[] cnt = new int[26];
            for (int i = 0; i < text.length(); i++) {
                char c = text.charAt(i);
                if (Character.isLetter(c)) {
                    cnt[Character.toLowerCase(c) - 'a']++;
                }
            }
            Integer[] letters = new Integer[26];
            for (int i = 0; i < 26; i++) letters[i] = i;
            Arrays.sort(letters, (a, b) -> {
                if (cnt[a] != cnt[b]) return Integer.compare(cnt[a], cnt[b]);
                return Integer.compare(a, b);
            });
            char[] map = new char[26];
            for (int i = 0; i < 26; i++) {
                map[letters[i]] = freqSeq.charAt(i);
            }
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < text.length(); i++) {
                char c = text.charAt(i);
                if (Character.isLetter(c)) {
                    char low = Character.toLowerCase(c);
                    char dec = map[low - 'a'];
                    if (Character.isUpperCase(c)) dec = Character.toUpperCase(dec);
                    sb.append(dec);
                } else sb.append(c);
            }
            out.append(sb);
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

