#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        freq_seq = data[idx].strip(); idx += 1
        text = data[idx]; idx += 1
        cnt = [0]*26
        for ch in text:
            if ch.isalpha():
                cnt[ord(ch.lower())-97] += 1
        letters = list(range(26))
        letters.sort(key=lambda x: (cnt[x], x))
        mapping = {chr(letters[i]+97): freq_seq[i] for i in range(26)}
        res_chars = []
        for ch in text:
            if ch.isalpha():
                low = ch.lower()
                dec = mapping[low]
                if ch.isupper():
                    dec = dec.upper()
                res_chars.append(dec)
            else:
                res_chars.append(ch)
        out_lines.append(''.join(res_chars))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

