const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').split(/\n/);
let ptr = 0;
const T = parseInt(input[ptr++].trim(), 10);
let results = [];
for (let tc = 0; tc < T; tc++) {
  const freqSeq = (input[ptr++] || '').trim();
  const text = (input[ptr++] || '');
  const cnt = new Array(26).fill(0);
  for (let ch of text) {
    if (/[a-zA-Z]/.test(ch)) {
      const low = ch.toLowerCase();
      cnt[low.charCodeAt(0) - 97]++;
    }
  }
  const letters = [...Array(26).keys()];
  letters.sort((a, b) => {
    if (cnt[a] !== cnt[b]) return cnt[a] - cnt[b];
    return a - b;
  });
  const map = new Array(26);
  for (let i = 0; i < 26; i++) {
    map[letters[i]] = freqSeq[i];
  }
  let decoded = '';
  for (let ch of text) {
    if (/[a-zA-Z]/.test(ch)) {
      const low = ch.toLowerCase();
      let dec = map[low.charCodeAt(0) - 97];
      if (ch >= 'A' && ch <= 'Z') dec = dec.toUpperCase();
      decoded += dec;
    } else {
      decoded += ch;
    }
  }
  results.push(decoded);
}
